import React, { useState, useEffect } from 'react';

const App = () => {
  const [items, setItems] = useState([]);
  const [refreshing, setRefreshing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Fetch initial data
  useEffect(() => {
    fetch('https://api.example.com/data')
      .then(res => res.json())
      .then(data => {
        setItems(data.items);
        setIsLoading(false);
      })
      .catch(err => console.error('Failed to fetch data:', err));
  }, []);

  // Handle pull-to-refresh
  const handleRefresh = () => {
    setRefreshing(true);
    setTimeout(() => {
      fetch('https://api.example.com/data')
        .then(res => res.json())
        .then(data => {
          setItems(data.items);
          setIsLoading(false);
          setRefreshing(false);
        })
        .catch(err => console.error('Failed to refresh data:', err));
    }, 1000);
  };

  return (
    <FlatList
      data={items}
      keyExtractor={(item, index) => item.id}
      renderItem={({ item }) => (
        <View>
          <Text>{item.name}</Text>
        </View>
      )}
      onRefresh={() => handleRefresh()}
      refreshControl={Platform.OS === 'ios' ? RefreshControl.IOSRefreshControl : null}
    />
  );
};

