// Function to save authentication token
const saveToken = async (token: string) => {
  try {
    const key = await useSecureStore('auth_token');
    if (!key) throw new Error('Authentication token not found');

    await useSecureStore.setItem('auth_token', token);
    return token;
  } catch (error) {
    console.error('Failed to save token:', error);
    throw error;
  }
};

// Function to retrieve authentication token
const getAccessToken = async () => {
  try {
    const token = await useSecureStore.getItem('auth_token');
    if (!token) throw new Error('Authentication token not found');

    return token;
  } catch (error) {
    console.error('Failed to retrieve token:', error);
    throw error;
  }
};

