const App = () => {
  const [position, setPosition] = React.useState({ x: 0 });

  const handlePress = () => {
    // Start scaling up
    Animated.spring(position.x, {
      toValue: position.x + 100,
      duration: 500,
      ease: 'easeInOut'
    }, () => {
      // Scale back down
      Animated.spring(position.x, {
        toValue: position.x - 100,
        duration: 500,
        ease: 'easeInOut'
      });
    });

    // Reset position for smooth animation
    setPosition({ x: 0 });
  };

  return (
    <View style={{ flex: 1 }}>
      <TouchableOpacity onPress={handlePress} style={{ width: 80, height: 80, backgroundColor: '#f00' }}>
        <Animated.View 
          style={{
            position: 'absolute',
            width: 80,
            height: 80,
            transform: [{ scale: position.x / 100 }]
          }}
        />
      </TouchableOpacity>
    </View>
  );
};

