import React from 'react';

const LoginForm = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState({ email: '', password: '' });

  // Validate email format
  const validateEmail = (value) => {
    if (!value || !/^[^\s@]+@[^\s]+\.[^a-z]+$/.test(value)) {
      return { email: 'Please enter a valid email address.' };
    }
    return null;
  };

  // Validate password length
  const validatePassword = (value) => {
    if (!value || value.length < 8) {
      return { password: 'Password must be at least 8 characters long.' };
    }
    return null;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const emailError = validateEmail(email);
    const passwordError = validatePassword(password);

    setErrors({ ...errors, email: emailError.email, password: passwordError.password });

    // Simulate form submission
    if (!email || !password) {
      return;
    }

    // For simplicity, we'll just show the errors and reset the state
    setEmail('');
    setPassword('');
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="email">Email</label>
        <input
          type="email"
          id="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          error={errors.email}
          required
        />
      </div>

      <div>
        <label htmlFor="password">Password</label>
        <input
          type="password"
          id="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          error={errors.password}
          required
        />
      </div>

      <button type="submit">Login</button>
    </form>
  );
};

export default LoginForm;

